// Extract and validate data from webhook
const body = $input.first().json.body || $input.first().json;
const { message, projectId, projectName, userId, userEmail, userName, teamMembers, projectData, humandChannelId } = body;

if (!message || !projectId) {
  return {
    error: true,
    errorMessage: 'Mensagem ou ID do projeto não fornecidos'
  };
}

// Format team members for context
const formattedTeamMembers = (teamMembers || []).map(m => ({
  id: m.id,
  name: m.name || m.full_name,
  email: m.email || '',
  role: m.role
}));

const teamMembersContext = formattedTeamMembers.length > 0
  ? formattedTeamMembers.map(m => `- ${m.name}${m.email ? ` (${m.email})` : ''} - ${m.role} [ID: ${m.id}]`).join('\n')
  : 'Nenhum membro de equipe associado a este projeto.';

// Format project stats
const stats = projectData?.stats || {};
const projectStatsContext = `
Estatísticas do Projeto:
- Total de tarefas: ${stats.total || 0}
- A fazer (todo): ${stats.todo || 0}
- Em progresso: ${stats.inProgress || 0}
- Em revisão: ${stats.review || 0}
- Concluídas: ${stats.done || 0}
- Bloqueadas: ${stats.blocked || 0}
- Pontos totais: ${stats.totalPoints || 0}
- Pontos concluídos: ${stats.completedPoints || 0}
- Percentual de conclusão: ${stats.completionPercentage || 0}%
`;

// Format workload
const workload = stats.workload || {};
const workloadContext = Object.keys(workload).length > 0
  ? Object.entries(workload)
      .sort((a, b) => b[1].points - a[1].points)
      .map(([name, data]) => `- ${name}: ${data.tasks} tarefas (${data.points} pontos)`)
      .join('\n')
  : 'Nenhuma tarefa atribuída no momento.';

// Format tasks lists
const todoTasks = (projectData?.todoTasks || []).slice(0, 10);
const inProgressTasks = projectData?.inProgressTasks || [];
const blockedTasks = projectData?.blockedTasks || [];

const todoContext = todoTasks.length > 0
  ? todoTasks.map(t => `- ${t.title}${t.assigned_to_name ? ` (${t.assigned_to_name})` : ''}`).join('\n')
  : 'Nenhuma tarefa a fazer.';

const inProgressContext = inProgressTasks.length > 0
  ? inProgressTasks.map(t => `- ${t.title}${t.assigned_to_name ? ` (${t.assigned_to_name})` : ''}`).join('\n')
  : 'Nenhuma tarefa em progresso.';

const blockedContext = blockedTasks.length > 0
  ? blockedTasks.map(t => `- ${t.title}${t.assigned_to_name ? ` (${t.assigned_to_name})` : ''}`).join('\n')
  : 'Nenhuma tarefa bloqueada.';

return {
  message: message.trim(),
  projectId,
  projectName: projectName || 'Projeto',
  userId,
  userEmail: userEmail || '',
  userName: userName || 'Usuário',
  teamMembers: formattedTeamMembers,
  teamMembersContext,
  projectStatsContext,
  workloadContext,
  todoContext,
  inProgressContext,
  blockedContext,
  hasProjectData: !!projectData,
  humandChannelId: humandChannelId || null,
  timestamp: new Date().toISOString()
};

