const response = $input.first().json.message?.content || '';
const originalData = $('Parse Input').first().json;

let result;

// Definição das expressões regulares para evitar erros de sintaxe
const regexMarkdown = /```json\s*([\s\S]*?)\s*```/;
const regexRawJson = /\{[\s\S]*"type"\s*:\s*"email"[\s\S]*\}/;

const jsonMatch = response.match(regexMarkdown) || response.match(regexRawJson);

if (jsonMatch) {
  try {
    const jsonStr = jsonMatch[1] || jsonMatch[0];
    const parsed = JSON.parse(jsonStr);

    if (parsed.type === 'email') {
      result = {
        ...originalData,
        type: 'email',
        recipients: parsed.recipients || [],
        recipientNames: parsed.recipientNames || parsed.recipients || [],
        subject: parsed.subject || 'Mensagem do Daher Plan',
        body: parsed.body || '',
        needsClarification: parsed.needsClarification || false,
        clarificationQuestion: parsed.clarificationQuestion || ''
      };
    } else {
      result = {
        ...originalData,
        type: 'answer',
        message: response.replace(/```json[\s\S]*?```/g, '').trim()
      };
    }
  } catch (e) {
    result = {
      ...originalData,
      type: 'answer',
      message: response
    };
  }
} else {
  result = {
    ...originalData,
    type: 'answer',
    message: response
  };
}

return result;

