return {
  success: true,
  type: 'clarification',
  message: data.clarificationQuestion || 'Poderia me dar mais detalhes sobre para quem você gostaria de enviar o e-mail?',
  timestamp: new Date().toISOString()
};

// Return answer response
const data = $input.first().json;

return {
  success: true,
  type: 'answer',
  message: data.message || 'Desculpe, não consegui processar sua pergunta.',
  timestamp: new Date().toISOString()
};

