// Idempotency-Key é obrigatório pela API da Humand (deve ser único por request)
const idempotencyKey = `${Date.now()}-${Math.random().toString(36).slice(2)}`;

const response = await fetch('https://api-prod.humand.co/public/api/v1/marty/chat.postMessage', {
  method: 'POST',
  headers: {
    'Authorization': 'Basic NTc1MDQwNTpTc2lRZlNrWlhaNmd4aEdwYWNBS3JJMUJac2M4eEZyMA==',
    'Content-Type': 'application/json',
    'Idempotency-Key': idempotencyKey
  },
  body: JSON.stringify({ channel, text, mrkdwn: false })
});

const result = await response.json();

if (response.ok && result.ok) {
  return { success: true, message: 'Mensagem enviada com sucesso no Humand', ts: result.ts };
} else {
  return { success: false, error: 'Falha ao enviar mensagem no Humand', details: result };
